use std::io::stdin;
fn main() {
    let mut text = String::new();
    stdin().read_line(&mut text).unwrap();
    let text = text.trim();
    let mut counter4: usize = 0;
    let mut counter7: usize = 0;
    for i in text.chars() {
        if '4' == i {
            counter4 += 1;
        } else if '7' == i {
            counter7 += 1;
        }
    }
    if counter4 == 0 && counter7 == 0 {
        println!("-1");
    } else if counter4 >= counter7 {
        println!("4")
    } else {
        println!("7")
    }
}

fn delete_leading_zeroes(arr: Vec<char>) -> Vec<char> {
    let mut finded = false;
    let mut last = 0;
    for i in 0..arr.len() {
        if '0' == arr[i] {
            continue;
        } else {
            last = i;
            finded = true;
            break;
        }
    }
    if finded {
        arr[last..].to_vec()
    } else {
        arr
    }
}
